import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { useAuth } from '../context/AuthContext';
import api from '../api';
import './Auth.css';

const ROLES = [
  { value: 'donor',     label: '🩸 Donor',     desc: 'I want to donate blood' },
  { value: 'patient',   label: '🏥 Patient',   desc: 'I need blood' },
  { value: 'hospital',  label: '🏨 Hospital',  desc: 'Managing blood requests' },
  { value: 'volunteer', label: '🤝 Volunteer', desc: 'Supporting the network' },
];

export default function Signup() {
  const { register, handleSubmit, watch, formState: { errors } } = useForm();
  const { login } = useAuth();
  const navigate = useNavigate();
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [selectedRole, setSelectedRole] = useState('');

  const onSubmit = async (data) => {
    if (!selectedRole) { setError('Please select a role'); return; }
    setError('');
    setLoading(true);
    try {
      const res = await api.post('/signup', { ...data, role: selectedRole });
      login(res.data.token, res.data.user);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Signup failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card auth-card-wide card">
        <div className="auth-header">
          <span className="auth-icon">🩸</span>
          <h1>LifeLink</h1>
          <p>Create your account</p>
        </div>

        {error && <div className="alert alert-error">{error}</div>}

        <form onSubmit={handleSubmit(onSubmit)}>
          <div className="grid-2">
            <div className="form-group">
              <label>Full Name</label>
              <input placeholder="John Doe" {...register('name', { required: 'Name is required' })} />
              {errors.name && <span className="error">{errors.name.message}</span>}
            </div>
            <div className="form-group">
              <label>Email address</label>
              <input type="email" placeholder="you@example.com" {...register('email', { required: 'Email is required' })} />
              {errors.email && <span className="error">{errors.email.message}</span>}
            </div>
            <div className="form-group">
              <label>Password</label>
              <input type="password" placeholder="Min 6 characters" {...register('password', { required: 'Password is required', minLength: { value: 6, message: 'Min 6 characters' } })} />
              {errors.password && <span className="error">{errors.password.message}</span>}
            </div>
            <div className="form-group">
              <label>Phone Number</label>
              <input placeholder="+1 555 000 0000" {...register('phone')} />
            </div>
          </div>

          <div className="form-group">
            <label>Location / City</label>
            <input placeholder="e.g. New York, NY" {...register('location')} />
          </div>

          <div className="form-group">
            <label>Select Your Role</label>
            <div className="role-grid">
              {ROLES.map(r => (
                <button
                  key={r.value}
                  type="button"
                  className={`role-card ${selectedRole === r.value ? 'selected' : ''}`}
                  onClick={() => setSelectedRole(r.value)}
                >
                  <span className="role-label">{r.label}</span>
                  <span className="role-desc">{r.desc}</span>
                </button>
              ))}
            </div>
          </div>

          <button type="submit" className="btn btn-primary btn-full" disabled={loading}>
            {loading ? <span className="spinner" /> : 'Create Account'}
          </button>
        </form>

        <p className="auth-footer">
          Already have an account? <Link to="/login">Sign in</Link>
        </p>
      </div>
    </div>
  );
}
